parameters.jsCode:
let raw = $json.choices[0].message.content;
let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = { erro: "Falha ao parsear JSON Redatora do DeepSeek" };
}

const input = $('Execute Workflow Trigger').item.json;
input.documentos_finais = parsed;

return { json: input };
